function changeLang(t){var e=new Translate,n=t;e.init("data-tag",n),e.process(),e.populate()}function Translate(){this.init=function(t,e){this.attribute=t,this.lang=e},this.process=function(){_self=this;var t=new XMLHttpRequest;t.open("GET","./language/"+this.lang+".json",!1),t.onreadystatechange=function(){if(4===t.readyState&&(200===t.status||0===t.status)){var e=JSON.parse(t.responseText);console.log(e.name1);for(var n=document.getElementsByTagName("*"),a=0;a<n.length;a++){var s=n[a],o=s.getAttribute(_self.attribute);null!=o&&(console.log(o),s.innerHTML=e[o])}}},t.send()},this.populate=function(){_self=this;var t=new XMLHttpRequest,e=`./language/${this.lang}-city.json`;t.onreadystatechange=function(){if(t.readyState===XMLHttpRequest.DONE&&200===t.status){var e=JSON.parse(t.responseText),n=document.getElementById("search");for(var a in e)n.innerHTML=`${n.innerHTML}<option>${e[a].name}</option>`}},t.open("GET",e,!0),t.send()}}function show(t){document.getElementById("results").innerHTML=t.value}